class Solution {
    public long[] unmarkedSumArray(int[] nums, int[][] queries) {
        int n = nums.length;
        int m = queries.length;
        long sumTotal = 0;
        PriorityQueue<int[]> heap = new PriorityQueue<>((a, b) -> {
            if (a[0] != b[0]) return a[0] - b[0];
            else return a[1] - b[1];
        });
        for (int i = 0; i < n; ++i) {
            sumTotal += nums[i];
            heap.offer(new int[]{nums[i], i});
        }
        boolean[] marked = new boolean[n];
        long[] res = new long[m];
        for (int q = 0; q < m; ++q) {
            int index = queries[q][0];
            int k = queries[q][1];
            if (!marked[index]) {
                sumTotal -= nums[index];
                marked[index] = true;
            }
            int count = 0;
            while (count < k && !heap.isEmpty()) {
                int[] el = heap.poll();
                int val = el[0];
                int idx = el[1];
                if (marked[idx]) continue;
                sumTotal -= val;
                marked[idx] = true;
                ++count;
            }
            res[q] = sumTotal;
        }
        return res;
    }
}

